#include <bits/stdc++.h>
using namespace std;

int main() {
    int T, p;
    int res;
    vector<int> t(12);

    for (int i = 0; i < 12; i++) {
        t[i] = (1 << i); // t[i] denotes pow(2,i)
    }

    cin >> T;
    assert(1 <= T && T <= 5);

    while (T--) {
        cin >> p;
        assert(1 <= p && p <= 100000);

        res = 0;
        for (int i = 11; i >= 0; i--) {
            res += p / t[i]; // p/t[i] (floor(p/t[i])) denotes the number of nemu i which Tomya orders
            p %= t[i];      // p decrease by used money
        }

        cout << res << std::endl;
    }

    return 0;
}

